"""Write declared scenarios to YAML files and stream-json fixtures on disk."""

import itertools
from collections import defaultdict
from pathlib import Path

from scripts.eval.corpus_gen.model import Scenario, fixture_stream, scenario_yaml

_GENERATED_HEADER = (
    "# GENERATED by scripts/eval/generate_corpus.py — do not edit by hand.\n"
    "# Edit the declaration in scripts/eval/corpus_gen/catalog.py and re-run\n"
    "# `uv run python scripts/eval/generate_corpus.py`.\n"
)


def _variants_for(scenario: Scenario) -> tuple[str, ...]:
    variants = ["fail", "pass"]
    if scenario.has_negative:
        variants.append("noop")
    return tuple(variants)


def emit_scenario(scenario: Scenario) -> dict[str, str]:
    """Return ``{filename: text}`` for one scenario's fixtures (no I/O)."""
    return {
        f"{scenario.name}_{variant}.stream.jsonl": fixture_stream(scenario, variant)
        for variant in _variants_for(scenario)
    }


def emit_catalog(
    scenarios: list[Scenario],
    *,
    scenarios_dir: Path,
    fixtures_dir: Path,
) -> tuple[dict[Path, str], dict[Path, str]]:
    """Render the whole catalog to ``({yaml_path: text}, {fixture_path: text})``.

    Pure: returns the intended file contents without touching disk so the
    generation test can diff against the committed tree.
    """
    by_file: dict[str, list[Scenario]] = defaultdict(list)
    for scenario in scenarios:
        by_file[scenario.yaml_file].append(scenario)
    yaml_files: dict[Path, str] = {}
    for filename, group in sorted(by_file.items()):
        body = "\n".join(scenario_yaml(s) for s in group)
        yaml_files[scenarios_dir / filename] = _GENERATED_HEADER + "\n" + body
    fixture_files: dict[Path, str] = {}
    for scenario in scenarios:
        for name, text in emit_scenario(scenario).items():
            fixture_files[fixtures_dir / name] = text
    return yaml_files, fixture_files


def write_catalog(scenarios: list[Scenario], *, scenarios_dir: Path, fixtures_dir: Path) -> list[Path]:
    """Write the catalog to disk and return every path written."""
    yaml_files, fixture_files = emit_catalog(scenarios, scenarios_dir=scenarios_dir, fixtures_dir=fixtures_dir)
    written: list[Path] = []
    for path, text in itertools.chain(yaml_files.items(), fixture_files.items()):
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(text, encoding="utf-8")
        written.append(path)
    return written
